var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"드디어 도착했네요.","JPN":"ようやく着きましたね。","ENG":"So we're finally here.","TWN":"終於到了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"미약하긴 하지만, 네임리스 원의 침식파 시그니처가 감지되고 있어요.","JPN":"微弱ではありますが、ネームレスワンの侵食波シグネチャーが検知されています。","ENG":"The radar has detected the Nameless One's Corruption ray signature, though it's very weak.","TWN":"雖然信號微弱，但重新監測到了無名1的侵蝕波信號。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그다지 먼 곳은 아니군요. 도보로 한 시간 정도면 도착할 수 있을 겁니다.","JPN":"さほど遠いところではないようです。徒歩で1時間程度で到着するでしょう。","ENG":"It's not that far away. Probably an hour's walk from here.","TWN":"離這裡並不遠。徒步的話大概一個小時左右就能到。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그런데 어째서 이런 곳에 함선을 착륙시킨 거지?","JPN":"ところで、どうしてこんな所に艦船を着陸させた？","ENG":"Then why did you land the ship here?","TWN":"可為什麼要讓艦船在這種地方著陸？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"더 가까이 갈 수는 없나?","JPN":"もっと近付けないのか？","ENG":"Couldn't we get any closer?","TWN":"不能再接近點嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"글레입니르는 뛰어난 함선이지만 이 정도의 고심도 강하에는 부하가 걸릴 수밖에 없어요.","JPN":"グレイプニルは優れた艦船ですが、このレベルの高深度降下にもなると負荷がかかります。","ENG":"Gleipnir is an excellent ship, but it's bound to be strained when diving this deep.","TWN":"格萊伊尼勒雖然是出色的艦船，但在這種超深度下降中也會超負荷。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"함선이 기능을 회복할 때까지는 여기서 잠시 대기해야 할 것 같군요.","JPN":"艦船の機能が回復するまでは、しばらくここで待機しなければならないようです。","ENG":"I'm afraid we'll have to wait here until the ship regains its functions.","TWN":"看來在艦船功能恢復之前，需要在這裡暫時等待了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"신호는 이 근방이라고 했나?","JPN":"シグナルはこの辺だと言ったな？","ENG":"Did you say the signals were detected around here?","TWN":"你說信號就在附近嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그렇습니다만. 설마하니, 직접 걸어서 갈 작정인가요?","JPN":"はい。まさか、本当に歩いていくつもりですか？","ENG":"Yes. Are you planning to walk all the way there?","TWN":"是的，難道，你打算親自走過去嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"시간을 낭비할 필요는 없으니까.","JPN":"時間を無駄にする必要はないだろう。","ENG":"There's no need to waste time.","TWN":"沒必要浪費時間。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"내가 먼저 놈의 유해를 확인하고 있겠다.","JPN":"私が先に行って奴の遺骸を確認する。","ENG":"I'll go check the Nameless One's remains first.","TWN":"我先過去確認那傢伙的遺骸。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"후훗......","JPN":"ふふっ……","ENG":"Hah hah...","TWN":"嘿嘿……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"뭐, 당신이라면 그럴 거라고 생각했습니다.","JPN":"まあ、あなたならそうすると思っていましたよ。","ENG":"Well, I figured you'd say that.","TWN":"嗯，我早就想到你會這麼做。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"무슨 뜻이지?","JPN":"どういう意味だ？","ENG":"What do you mean?","TWN":"什麼？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신이 이곳에서 찾고 있는 건 네임리스 원의 유해뿐이 아니라는 뜻이죠.","JPN":"あなたがここで探しているのは、ネームレスワンの遺骸だけではないという意味です。","ENG":"You're not just looking for the Nameless One's remains, are you?","TWN":"我的意思是，你來這裡尋找的並不僅僅是無名1的遺骸。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"도착하기 전에 당신이 했던 질문이 그저 심심풀이를 위한 잡담은 아니었을 테니까요.","JPN":"到着する前にあなたがした質問は、ただの退屈しのぎのための雑談ではないはずです。","ENG":"The question you asked before we arrived here—you didn't bring it up just to pass the time.","TWN":"在到達之前你問的問題，肯定不是為了閒聊而已。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이 우주에서, 시간의 흐름이란 건 장소에 따라 상대적입니다. 이면세계도 예외는 아니죠.","JPN":"この宇宙において、時間の流れというものは場所によって相対的なものです。それは裏世界も例外ではありません。","ENG":"In this universe, the flow of time is relative to the location. The Counterside is no exception.","TWN":"在這個宇宙中，根據場所的變化，時間的流轉是相對的。異界也不例外。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"우연인지 필연인지...... 글레입니르의 전술 컴퓨터가 분석한 바에 따르면 이 좌표는 현실세계에 비해 시간이 훨씬 느리게 흐른다고 하는군요.","JPN":"偶然か必然か……グレイプニルの戦術コンピューターが分析したところ、この座標は現実世界に比べて時間の流れがはるかに遅いようです。","ENG":"Whether by fate or coincidence... analysis by Gleipnir's Tactical C4I shows that the flow of time is much slower at these coordinates than in the Normalside.","TWN":"不知道是偶然還是必然……根據格萊伊尼勒的戰術電腦分析，這個座標相對現實世界來說時間的流速非常緩慢。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};